using System;
using System.Data;
using System.Threading;
using System.Threading.Tasks;
using Microsoft.Data.SqlClient;

public static class StreamVersionRepository
{
    /// <summary>
    /// Retrieves the next version number for a given stream.
    /// Returns -1 if no further versions are available.
    /// </summary>
    /// <param name="connectionString">SQL database connection string.</param>
    /// <param name="streamId">Identifier of the stream.</param>
    /// <param name="currentVersion">Current version number of the stream.</param>
    /// <param name="cancellationToken">Optional cancellation token.</param>
    /// <returns>Next version number or -1 if none exists.</returns>
    public static async Task<int> GetNextVersionAsync(
        string connectionString,
        Guid streamId,
        int currentVersion,
        CancellationToken cancellationToken = default)
    {
        const string sql = @"
            SELECT TOP 1 VersionNumber
            FROM StreamVersions
            WHERE StreamId = @StreamId
              AND VersionNumber > @CurrentVersion
            ORDER BY VersionNumber ASC;";

        await using var connection = new SqlConnection(connectionString);
        await connection.OpenAsync(cancellationToken).ConfigureAwait(false);

        await using var command = new SqlCommand(sql, connection)
        {
            CommandType = CommandType.Text,
            CommandTimeout = 30
        };

        command.Parameters.Add(new SqlParameter("@StreamId", SqlDbType.UniqueIdentifier) { Value = streamId });
        command.Parameters.Add(new SqlParameter("@CurrentVersion", SqlDbType.Int) { Value = currentVersion });

        var result = await command.ExecuteScalarAsync(cancellationToken).ConfigureAwait(false);

        return result is int nextVersion ? nextVersion : -1;
    }
}
