{
    public int Id { get; set; }

    [Required]
    [MaxLength(100)]
    public string Name { get; set; } = string.Empty;

    [Range(0, 120)]
    public int Age { get; set; }

    [Required]
    [EmailAddress]
    public string Email { get; set; } = string.Empty;
}

public class AppDbContext : DbContext
{
    public DbSet<MyEntity> MyEntities => Set<MyEntity>();

    // Configure your DB connection here (e.g., OnConfiguring or via DI)
}

public static class EntityService
{
    private static readonly Regex EmailRegex = new(@"^[^@\s]+@[^@\s]+\.[^@\s]+$", RegexOptions.Compiled);

    public static async Task<(bool Success, string? ErrorMessage)> CreateEntityAsync(InputModel input)
    {
        // Input validation
        var validationResults = ValidateInput(input);
        if (validationResults != null)
        {
            return (false, validationResults);
        }

        try
        {
            await using var db = new AppDbContext();

            var entity = new MyEntity
            {
                Name = input.Name.Trim(),
                Age = input.Age,
                Email = input.Email.Trim()
            };

            db.MyEntities.Add(entity);
            await db.SaveChangesAsync();

            return (true, null);
        }
        catch (DbUpdateException ex)
        {
            // Log exception securely (omitted for brevity)
            return (false, "Database update failed.");
        }
        catch (Exception)
        {
            // Log unexpected exceptions securely (omitted for brevity)
            return (false, "An unexpected error occurred.");
        }
    }

    private static string? ValidateInput(InputModel input)
    {
        if (string.IsNullOrWhiteSpace(input.Name))
            return "Name must not be empty.";

        if (input.Name.Length > 100)
            return "Name exceeds maximum length of 100 characters.";

        if (input.Age < 0 || input.Age > 120)
            return "Age must be between 0 and 120.";

        if (string.IsNullOrWhiteSpace(input.Email))
            return "Email must not be empty.";

        if (!EmailRegex.IsMatch(input.Email))
            return "Email format is invalid.";

        return null;
    }
