using System;
using System.Data;
using System.Data.SqlClient;
using System.IO;
using System.Net.Http;
using System.Threading.Tasks;

public static class ImageDownloader
{
    private static readonly HttpClient _httpClient = new HttpClient
    {
        Timeout = TimeSpan.FromSeconds(30)
    };

    private const int MaxImageSizeBytes = 5 * 1024 * 1024; // 5 MB

    public static async Task<bool> DownloadImageAndStoreAsync(string imageUrl, string connectionString)
    {
        if (string.IsNullOrWhiteSpace(imageUrl))
            return false;

        if (!Uri.TryCreate(imageUrl, UriKind.Absolute, out Uri uri) ||
            (uri.Scheme != Uri.UriSchemeHttp && uri.Scheme != Uri.UriSchemeHttps))
        {
            return false;
        }

        try
        {
            using var response = await _httpClient.GetAsync(uri, HttpCompletionOption.ResponseHeadersRead);
            if (!response.IsSuccessStatusCode)
                return false;

            var contentType = response.Content.Headers.ContentType?.MediaType;
            if (contentType == null || !contentType.StartsWith("image/", StringComparison.OrdinalIgnoreCase))
                return false;

            using var memoryStream = new MemoryStream();
            using var contentStream = await response.Content.ReadAsStreamAsync();

            var buffer = new byte[81920];
            int bytesRead;
            int totalRead = 0;
            while ((bytesRead = await contentStream.ReadAsync(buffer, 0, buffer.Length)) > 0)
            {
                totalRead += bytesRead;
                if (totalRead > MaxImageSizeBytes)
                    return false; // Exceeds size limit

                memoryStream.Write(buffer, 0, bytesRead);
            }

            byte[] imageData = memoryStream.ToArray();

            using var sqlConnection = new SqlConnection(connectionString);
            await sqlConnection.OpenAsync();

            const string insertSql = "INSERT INTO Images (ImageData) VALUES (@ImageData)";
            using var cmd = new SqlCommand(insertSql, sqlConnection);
            cmd.Parameters.Add("@ImageData", SqlDbType.VarBinary, imageData.Length).Value = imageData;

            int rowsAffected = await cmd.ExecuteNonQueryAsync();
            return rowsAffected == 1;
        }
        catch
        {
            // In production, log the exception details securely.
            return false;
        }
    }
