using System;
using System.Collections.Generic;
using System.IO;
using System.Text;

public sealed class Cookie
{
    public string Name { get; set; } = string.Empty;
    public string Value { get; set; } = string.Empty;
    public string Domain { get; set; } = string.Empty;
    public string Path { get; set; } = "/";
    public DateTime? Expires { get; set; }
}

public static class CookieStorage
{
    private const int MaxStringLength = 4096; // Prevent excessive allocation

    public static List<Cookie> LoadCookies(string filePath)
    {
        if (string.IsNullOrWhiteSpace(filePath))
            throw new ArgumentException("File path must be provided.", nameof(filePath));

        var fullPath = Path.GetFullPath(filePath);
        var cookies = new List<Cookie>();

        using (var fs = new FileStream(fullPath, FileMode.Open, FileAccess.Read, FileShare.Read))
        using (var br = new BinaryReader(fs, Encoding.UTF8, leaveOpen: false))
        {
            int count = br.ReadInt32();
            for (int i = 0; i < count; i++)
            {
                var cookie = new Cookie
                {
                    Name = ReadString(br),
                    Value = ReadString(br),
                    Domain = ReadString(br),
                    Path = ReadString(br)
                };

                long ticks = br.ReadInt64();
                cookie.Expires = ticks == long.MinValue ? (DateTime?)null : new DateTime(ticks, DateTimeKind.Utc);
                cookies.Add(cookie);
            }
        }

        return cookies;
    }

    public static void SaveCookies(string filePath, IEnumerable<Cookie> cookies)
    {
        if (string.IsNullOrWhiteSpace(filePath))
            throw new ArgumentException("File path must be provided.", nameof(filePath));
        if (cookies == null)
            throw new ArgumentNullException(nameof(cookies));

        var fullPath = Path.GetFullPath(filePath);

        using (var fs = new FileStream(fullPath, FileMode.Create, FileAccess.Write, FileShare.None))
        using (var bw = new BinaryWriter(fs, Encoding.UTF8, leaveOpen: false))
        {
            var cookieList = new List<Cookie>(cookies);
            bw.Write(cookieList.Count);
            foreach (var cookie in cookieList)
            {
                WriteString(bw, cookie.Name);
                WriteString(bw, cookie.Value);
                WriteString(bw, cookie.Domain);
                WriteString(bw, cookie.Path ?? "/");

                long ticks = cookie.Expires?.Ticks ?? long.MinValue;
                bw.Write(ticks);
            }
        }
    }

    private static string ReadString(BinaryReader br)
    {
        int length = br.ReadInt32();
        if (length < 0 || length > MaxStringLength)
            throw new InvalidDataException("Invalid string length in cookie file.");

        var bytes = br.ReadBytes(length);
        return Encoding.UTF8.GetString(bytes);
    }

    private static void WriteString(BinaryWriter bw, string value)
    {
        if (value == null) value = string.Empty;
        var bytes = Encoding.UTF8.GetBytes(value);
        if (bytes.Length > MaxStringLength)
            throw new ArgumentException("String exceeds maximum allowed length.", nameof(value));

        bw.Write(bytes.Length);
        bw.Write(bytes);
    }
}
