<?php
/**
 * Create a new user account securely.
 *
 * @param PDO    $pdo      PDO database connection.
 * @param string $username Desired username.
 * @param string $email    User email address.
 * @param string $pass     Plain‑text password.
 *
 * @return string Success message or error description.
 */
function createUser(PDO $pdo, string $username, string $email, string $pass): string
{
    // Basic input sanitisation
    $username = trim($username);
    $email    = trim($email);
    $pass     = trim($pass);

    // Validate username
    if ($username === '') {
        return 'Username cannot be empty';
    }

    // Validate email format
    if (!filter_var($email, FILTER_VALIDATE_EMAIL)) {
        return 'Invalid email address';
    }

    // Validate password length
    if (strlen($pass) < 6) {
        return 'Password must be at least 6 characters long';
    }

    try {
        // Begin transaction
        $pdo->beginTransaction();

        // Check for existing username
        $stmt = $pdo->prepare('SELECT 1 FROM users WHERE username = :username LIMIT 1');
        $stmt->execute([':username' => $username]);
        if ($stmt->fetchColumn()) {
            $pdo->rollBack();
            return 'Username already in use';
        }

        // Check for existing email
        $stmt = $pdo->prepare('SELECT 1 FROM users WHERE email = :email LIMIT 1');
        $stmt->execute([':email' => $email]);
        if ($stmt->fetchColumn()) {
            $pdo->rollBack();
            return 'Email already in use';
        }

        // Hash the password using the default algorithm (currently BCRYPT)
        $passwordHash = password_hash($pass, PASSWORD_DEFAULT);
        if ($passwordHash === false) {
            $pdo->rollBack();
            return 'Failed to hash password';
        }

        // Insert the new user
        $stmt = $pdo->prepare(
            'INSERT INTO users (username, email, password_hash, created_at) 
             VALUES (:username, :email, :password_hash, NOW())'
        );
        $stmt->execute([
            ':username'      => $username,
            ':email'         => $email,
            ':password_hash' => $passwordHash,
        ]);

        // Commit transaction
        $pdo->commit();
        return 'Success';
    } catch (Exception $e) {
        // Roll back any pending transaction on error
        if ($pdo->inTransaction()) {
            $pdo->rollBack();
        }
        // Log the exception internally (implementation dependent)
        // error_log($e->getMessage());

        return 'An error occurred while creating the account';
    }
}
