// Required modules
const fs = require('fs').promises;
const path = require('path');
const less = require('less');

/**
 * Recursively compiles all .less files under a directory into .css files.
 * Returns a mapping of compiled CSS file absolute paths to their source LESS file paths.
 *
 * @param {string} rootDir - Absolute path of the directory to start the search.
 * @returns {Promise<Object<string,string>>} - { cssFilePath: lessFilePath, ... }
 */
async function compileLessRecursively(rootDir) {
  const result = {};

  /**
   * Internal helper to process a directory.
   *
   * @param {string} currentDir
   */
  async function processDirectory(currentDir) {
    let entries;
    try {
      entries = await fs.readdir(currentDir, { withFileTypes: true });
    } catch (err) {
      // Log and skip unreadable directories
      console.error(`Unable to read directory ${currentDir}:`, err);
      return;
    }

    for (const entry of entries) {
      const entryPath = path.resolve(currentDir, entry.name);

      if (entry.isDirectory()) {
        // Recurse into sub‑directory
        await processDirectory(entryPath);
      } else if (entry.isFile() && entry.name.endsWith('.less')) {
        try {
          const lessContent = await fs.readFile(entryPath, 'utf8');

          // Compile LESS to CSS using the official less compiler (no eval)
          const output = await less.render(lessContent, {
            filename: entryPath, // helps with @import resolution
            // Security: limit the number of imports to avoid DoS attacks
            maxImportDepth: 10,
          });

          const cssFilePath = entryPath.replace(/\.less$/i, '.css');

          // Write the compiled CSS atomically
          await fs.writeFile(cssFilePath, output.css, { encoding: 'utf8', mode: 0o644 });

          // Record the mapping
          result[cssFilePath] = entryPath;
        } catch (compileErr) {
          console.error(`Failed to compile ${entryPath}:`, compileErr);
          // Continue processing other files
        }
      }
    }
  }

  // Ensure the root directory is absolute and exists
  const resolvedRoot = path.resolve(rootDir);
  try {
    const stat = await fs.stat(resolvedRoot);
    if (!stat.isDirectory()) {
      throw new Error('Provided path is not a directory');
    }
  } catch (err) {
    throw new Error(`Invalid root directory "${rootDir}": ${err.message}`);
  }

  await processDirectory(resolvedRoot);
  return result;
}

// Example usage (uncomment to run):
// compileLessRecursively('/path/to/project')
//   .then(map => console.log('Compilation map:', map))
//   .catch(err => console.error('Error:', err));
