import java.io.DataInputStream;
import java.io.IOException;
import java.io.InputStream;
import java.nio.charset.StandardCharsets;
import java.util.Collections;
import java.util.HashMap;
import java.util.Map;

public class MapMerger {

    /**
     * Merges a {@code Map<String, String>} with a binary stream that encodes a {@code Map<String, Byte>}.
     * The binary format is:
     * <pre>
     * int entryCount
     * repeat entryCount times:
     *   int keyLength (bytes)
     *   byte[keyLength] key (UTF‑8)
     *   byte value
     * </pre>
     *
     * @param stringMap   map whose values are parsed as {@code Byte}s (base‑10). Invalid entries are ignored.
     * @param binaryStream input stream containing the binary map representation.
     * @return an unmodifiable map containing the merged entries. Entries from the binary map
     *         overwrite those from {@code stringMap} when keys collide.
     * @throws IOException if an I/O error occurs while reading the binary stream.
     */
    public static Map<String, Byte> mergeMaps(Map<String, String> stringMap,
                                              InputStream binaryStream) throws IOException {
        // Defensive copy of the string map, converting values to Byte where possible.
        Map<String, Byte> result = new HashMap<>();
        if (stringMap != null) {
            for (Map.Entry<String, String> e : stringMap.entrySet()) {
                if (e.getKey() == null) {
                    continue; // skip null keys
                }
                try {
                    byte b = Byte.parseByte(e.getValue().trim());
                    result.put(e.getKey(), b);
                } catch (NumberFormatException ignored) {
                    // Invalid byte representation – skip this entry.
                }
            }
        }

        // Deserialize the binary map safely.
        if (binaryStream != null) {
            try (DataInputStream dis = new DataInputStream(binaryStream)) {
                int entryCount = dis.readInt();
                // Guard against unreasonable sizes (e.g., >10,000 entries).
                if (entryCount < 0 || entryCount > 10_000) {
                    throw new IOException("Invalid entry count in binary map: " + entryCount);
                }

                for (int i = 0; i < entryCount; i++) {
                    int keyLen = dis.readInt();
                    if (keyLen <= 0 || keyLen > 1_024) {
                        throw new IOException("Invalid key length: " + keyLen);
                    }
                    byte[] keyBytes = new byte[keyLen];
                    dis.readFully(keyBytes);
                    String key = new String(keyBytes, StandardCharsets.UTF_8);
                    byte value = dis.readByte();

                    if (key != null) {
                        result.put(key, value); // binary map overrides string map on conflict
                    }
                }
            }
        }

        return Collections.unmodifiableMap(result);
    }
}
