#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <netdb.h>
#include <arpa/inet.h>
#include <errno.h>

#define MAX_PATH 256
#define MAX_ADDR_STR 128

typedef struct {
    char config_path[MAX_PATH];
    char log_path[MAX_PATH];
    char service_root[MAX_PATH];
    struct sockaddr_storage dest_addr;
    socklen_t dest_addr_len;
    int has_dest;
} context_t;

/* Initialize the context with provided paths. */
static int init_context(context_t *ctx,
                        const char *config,
                        const char *log,
                        const char *root)
{
    if (!ctx || !config || !log || !root) return -1;

    memset(ctx, 0, sizeof(*ctx));

    /* Use snprintf to guarantee null‑termination and avoid overflow. */
    if (snprintf(ctx->config_path, sizeof(ctx->config_path), "%s", config) < 0) return -1;
    if (snprintf(ctx->log_path, sizeof(ctx->log_path), "%s", log) < 0) return -1;
    if (snprintf(ctx->service_root, sizeof(ctx->service_root), "%s", root) < 0) return -1;

    ctx->has_dest = 0;
    return 0;
}

/* Resolve and store the destination address. */
static int set_destination(context_t *ctx, const char *addr_str)
{
    if (!ctx || !addr_str) return -1;

    struct addrinfo hints = {0}, *res = NULL;
    hints.ai_family   = AF_UNSPEC;   /* Allow IPv4 or IPv6 */
    hints.ai_socktype = SOCK_STREAM; /* Stream socket (TCP) */

    int rc = getaddrinfo(addr_str, NULL, &hints, &res);
    if (rc != 0) {
        fprintf(stderr, "getaddrinfo error: %s\n", gai_strerror(rc));
        return -1;
    }

    memcpy(&ctx->dest_addr, res->ai_addr, res->ai_addrlen);
    ctx->dest_addr_len = (socklen_t)res->ai_addrlen;
    ctx->has_dest = 1;

    freeaddrinfo(res);
    return 0;
}

/* Simple demonstration of the initialized context. */
static void print_context(const context_t *ctx)
{
    printf("Config Path : %s\n", ctx->config_path);
    printf("Log Path    : %s\n", ctx->log_path);
    printf("Service Root: %s\n", ctx->service_root);

    if (ctx->has_dest) {
        char addr_buf[MAX_ADDR_STR];
        void *src = NULL;

        if (ctx->dest_addr.ss_family == AF_INET) {
            src = &((struct sockaddr_in *)&ctx->dest_addr)->sin_addr;
        } else if (ctx->dest_addr.ss_family == AF_INET6) {
            src = &((struct sockaddr_in6 *)&ctx->dest_addr)->sin6_addr;
        }

        if (src && inet_ntop(ctx->dest_addr.ss_family, src, addr_buf, sizeof(addr_buf))) {
            printf("Destination : %s\n", addr_buf);
        } else {
            printf("Destination : (unrecognized format)\n");
        }
    }
}

int main(int argc, char *argv[])
{
    if (argc < 4) {
        fprintf(stderr,
                "Usage: %s <config_path> <log_path> <service_root> [dest_address]\n",
                argv[0]);
        return EXIT_FAILURE;
    }

    context_t ctx;
    if (init_context(&ctx, argv[1], argv[2], argv[3]) != 0) {
        fprintf(stderr, "Failed to initialize context.\n");
        return EXIT_FAILURE;
    }

    if (argc >= 5) {
        if (set_destination(&ctx, argv[4]) != 0) {
            fprintf(stderr, "Failed to set destination address.\n");
            return EXIT_FAILURE;
        }
    }

    print_context(&ctx);
    return EXIT_SUCCESS;
}
