// Delegate type expected for the producer
public delegate Observation DemuxProducer<TInput, TOutput>(TInput input);

public static class ProducerFactory
{
    // Shared sequence counter
    private static long _globalSequence = 0;

    // Thread‑local Random instance for safe concurrent use
    private static readonly ThreadLocal<Random> _rng = new(() => new Random());

    // Implementation of the producer
    public static Observation Produce(int input)
    {
        // Start latency measurement
        var sw = Stopwatch.StartNew();

        // Increment the global sequence atomically
        long seq = Interlocked.Increment(ref _globalSequence);

        // Simulate work with a random delay (1‑100 ms)
        int delayMs = _rng.Value.Next(1, 101);
        Thread.Sleep(delayMs);

        // Stop latency measurement
        sw.Stop();

        // Build and return the observation
        return new Observation
        {
            SequenceNumber = seq,
            ProducerThreadId = Thread.CurrentThread.ManagedThreadId,
            LatencyMs = sw.ElapsedMilliseconds
        };
    }

    // Expose the method as a DemuxProducer delegate
    public static readonly DemuxProducer<int, Observation> Instance = Produce;
}
