/*
 * Returns a newly allocated string containing `input` with a '/' appended,
 * provided the length of `input` does not exceed `limit`.
 * Returns NULL if `input` is NULL, exceeds `limit`, or on allocation failure.
 * Caller is responsible for freeing the returned string.
 */
char *append_slash_if_within_limit(const char *input, size_t limit) {
    if (input == NULL) {
        return NULL;
    }

    /* Determine the length without exceeding the limit + 1 */
    size_t len = strnlen(input, limit + 1);
    if (len > limit) {
        return NULL; /* input exceeds the allowed size */
    }

    /* Check for size overflow when adding '/' and terminating NUL */
    if (len > SIZE_MAX - 2) {
        return NULL;
    }

    size_t new_len = len + 2; /* slash + NUL */
    char *result = (char *)malloc(new_len);
    if (result == NULL) {
        return NULL; /* allocation failed */
    }

    memcpy(result, input, len);
    result[len] = '/';
    result[len + 1] = '\0';

    return result;
}
