const path = require('path');

/**
 * Processes file content by Base64‑encoding it, writes the result to a new file,
 * and returns a configuration object with the file name and processed content.
 *
 * @param {Object} params
 * @param {string} params.content   - The original file content.
 * @param {string} params.fileName  - Desired name for the new file.
 * @param {string} [params.outputDir='.'] - Directory where the file will be created.
 * @returns {Promise<Object>} Configuration object containing the safe file name and Base64 content.
 */
async function processAndSaveFile({ content, fileName, outputDir = '.' }) {
  if (typeof content !== 'string') {
    throw new TypeError('content must be a string');
  }
  if (typeof fileName !== 'string') {
    throw new TypeError('fileName must be a string');
  }

  // Prevent path traversal by stripping directory components
  const safeFileName = path.basename(fileName);

  // Encode content securely
  const encodedContent = Buffer.from(content, 'utf8').toString('base64');

  // Resolve the full output path safely
  const outputPath = path.resolve(outputDir, safeFileName);

  // Write the file with restrictive permissions (read/write for owner only)
  await fs.writeFile(outputPath, encodedContent, { mode: 0o600 });

  return {
    fileName: safeFileName,
    processedContent: encodedContent,
  };
}
