/**
 * Retrieve user settings as boolean flags.
 *
 * @param PDO    $pdo       PDO database connection.
 * @param int    $userId    ID of the user.
 * @param string $tableName Name of the settings table (must be whitelisted).
 * @param array  $fields    List of column names to check.
 *
 * @return array Associative array where each key is a field name and the value is a boolean.
 *
 * @throws InvalidArgumentException If the table name is not allowed.
 * @throws RuntimeException         If the query fails.
 */
function getUserSettings(PDO $pdo, int $userId, string $tableName, array $fields): array
{
    // ---- Whitelist allowed tables to prevent injection via table name ----
    $allowedTables = ['user_settings', 'profile_settings']; // extend as needed
    if (!in_array($tableName, $allowedTables, true)) {
        throw new InvalidArgumentException('Invalid table name.');
    }

    // ---- Safely build the column list (column names are trusted from $fields) ----
    $escapedColumns = array_map(
        fn(string $col) => "`" . str_replace("`", "``", $col) . "`",
        $fields
    );
    $columnList = implode(', ', $escapedColumns);

    // ---- Prepare and execute the query using a bound parameter for user ID ----
    $sql  = "SELECT $columnList FROM `$tableName` WHERE user_id = :userId LIMIT 1";
    $stmt = $pdo->prepare($sql);
    $stmt->bindValue(':userId', $userId, PDO::PARAM_INT);

    if (!$stmt->execute()) {
        $errorInfo = $stmt->errorInfo();
        throw new RuntimeException('Database query failed: ' . $errorInfo[2]);
    }

    $row = $stmt->fetch(PDO::FETCH_ASSOC) ?: [];

    // ---- Convert each field presence/value to a boolean ----
    $result = [];
    foreach ($fields as $field) {
        $result[$field] = !empty($row[$field]);
    }

    return $result;
}
