use std::env;
use std::fs;
use std::path::{Path, PathBuf};

/// Returns the full path to an executable with the given `name` found in the
/// current working directory or the Cargo manifest directory.
/// Returns `None` if no such executable is found.
///
/// The function sanitizes `name` to prevent directory traversal attacks and
/// checks for executable permissions on Unix-like systems.
pub fn find_executable(name: &str) -> Option<PathBuf> {
    // Reject names that contain path separators or parent‑directory components.
    if name.contains('/') || name.contains('\\') || name.contains("..") {
        return None;
    }

    // Build the list of directories to search.
    let mut dirs = Vec::new();

    // Current working directory.
    if let Ok(cwd) = env::current_dir() {
        dirs.push(cwd);
    }

    // Cargo manifest directory (the directory containing Cargo.toml).
    if let Ok(manifest_dir) = env::var("CARGO_MANIFEST_DIR") {
        dirs.push(PathBuf::from(manifest_dir));
    }

    // Platform‑specific executable suffix.
    #[cfg(windows)]
    const EXE_SUFFIX: &str = ".exe";
    #[cfg(not(windows))]
    const EXE_SUFFIX: &str = "";

    // Iterate over directories and look for the executable.
    for dir in dirs {
        let candidate = dir.join(format!("{}{}", name, EXE_SUFFIX));

        // Use metadata to avoid following symlinks unintentionally.
        if let Ok(metadata) = fs::metadata(&candidate) {
            if metadata.is_file() {
                #[cfg(unix)]
                {
                    use std::os::unix::fs::PermissionsExt;
                    // Check execute bits for the current user.
                    if metadata.permissions().mode() & 0o111 != 0 {
                        return Some(candidate);
                    }
                }
                #[cfg(windows)]
                {
                    // On Windows, existence of the file with .exe suffix is sufficient.
                    return Some(candidate);
                }
            }
        }
    }

    None
}
