#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <string.h>
#include <errno.h>

int create_and_remove_temp(char *path_buf, size_t bufsize)
{
    if (path_buf == NULL || bufsize == 0) {
        errno = EINVAL;
        return -1;
    }

    /* Template must end with six X characters for mkstemp */
    const char *template = "/tmp/tmpfile_XXXXXX";
    size_t tmpl_len = strlen(template) + 1; /* include null terminator */

    if (bufsize < tmpl_len) {
        errno = ENAMETOOLONG;
        return -1;
    }

    /* Copy template into the caller's buffer */
    memcpy(path_buf, template, tmpl_len);

    /* mkstemp creates the file with mode 0600 and returns an open fd */
    int fd = mkstemp(path_buf);
    if (fd == -1) {
        return -1; /* errno already set by mkstemp */
    }

    /* Close the file descriptor; the file still exists on disk */
    if (close(fd) == -1) {
        /* Attempt to unlink before returning error */
        unlink(path_buf);
        return -1;
    }

    /* Unlink (delete) the file from the filesystem */
    if (unlink(path_buf) == -1) {
        return -1; /* errno set by unlink */
    }

    /* At this point the file is removed; the name remains in path_buf */
    return 0;
}
