public class PackageInfo {

    /**
     * Executes the system package manager to retrieve a list of installed packages.
     * This implementation uses a fixed, known-safe command and does not accept external input,
     * mitigating command injection risks.
     *
     * @return a list of strings, each representing a line of package information
     * @throws IOException if an I/O error occurs while reading the process output
     * @throws InterruptedException if the current thread is interrupted while waiting for the process
     */
    public static List<String> getInstalledPackages() throws IOException, InterruptedException {
        // Adjust the command according to the target OS/package manager.
        // Example for Debian-based systems: dpkg -l
        // Example for RPM-based systems: rpm -qa
        ProcessBuilder pb = new ProcessBuilder("dpkg", "-l");
        pb.redirectErrorStream(true); // Merge stderr with stdout for unified handling

        List<String> packages = new ArrayList<>();

        Process process = null;
        try {
            process = pb.start();

            // Use try-with-resources to ensure the stream is closed properly
            try (BufferedReader reader = new BufferedReader(
                    new InputStreamReader(process.getInputStream()))) {
                String line;
                while ((line = reader.readLine()) != null) {
                    packages.add(line);
                }
            }

            // Wait for the process to complete and check exit status
            int exitCode = process.waitFor();
            if (exitCode != 0) {
                throw new IOException("Package manager command exited with non-zero status: " + exitCode);
            }
        } finally {
            // Ensure the process is destroyed to free system resources
            if (process != null) {
                process.destroy();
            }
        }

        return packages;
    }
}
