import java.io.InputStream;
import java.io.IOException;
import java.net.URL;
import java.net.URLConnection;
import java.net.MalformedURLException;
import java.util.Objects;

/**
 * Utility class for loading resources securely.
 */
public final class ResourceLoader {

    private static final int CONNECT_TIMEOUT_MS = 5_000; // 5 seconds
    private static final int READ_TIMEOUT_MS    = 15_000; // 15 seconds

    private ResourceLoader() {
        // Prevent instantiation
    }

    /**
     * Returns an {@link InputStream} for the given {@code resourcePath}.
     * <p>
     * The method first attempts to load the resource from the classpath (relative to
     * the calling class). If that fails, it treats {@code resourcePath} as a URL and
     * attempts to open a connection using only the {@code http} or {@code https}
     * protocols.
     *
     * @param resourcePath a classpath-relative path or an absolute URL
     * @return an {@link InputStream} for reading the resource
     * @throws IOException if the resource cannot be found or read
     * @throws IllegalArgumentException if {@code resourcePath} is null or uses an
     *         unsupported protocol
     */
    public static InputStream getResourceAsStream(String resourcePath) throws IOException {
        Objects.requireNonNull(resourcePath, "resourcePath must not be null");

        // 1. Try loading from the classpath (relative to this class)
        InputStream classpathStream = ResourceLoader.class.getResourceAsStream(resourcePath);
        if (classpathStream != null) {
            return classpathStream;
        }

        // 2. Treat the string as a URL – only allow http/https
        URL url;
        try {
            url = new URL(resourcePath);
        } catch (MalformedURLException e) {
            throw new IOException("Invalid URL or resource not found: " + resourcePath, e);
        }

        String protocol = url.getProtocol().toLowerCase();
        if (!("http".equals(protocol) || "https".equals(protocol))) {
            throw new IllegalArgumentException("Unsupported URL protocol: " + protocol);
        }

        // 3. Open a connection with safe defaults
        URLConnection connection = url.openConnection();
        connection.setConnectTimeout(CONNECT_TIMEOUT_MS);
        connection.setReadTimeout(READ_TIMEOUT_MS);
        // Disallow automatic redirects to reduce SSRF surface
        if (connection instanceof java.net.HttpURLConnection) {
            ((java.net.HttpURLConnection) connection).setInstanceFollowRedirects(false);
        }

        // 4. Return the input stream; caller is responsible for closing it
        return connection.getInputStream();
    }
}
