/* 
 * Creates a POSIX unnamed semaphore with the given initial value,
 * performs a simple wait/post sequence, and destroys the semaphore.
 * Returns 0 on success, or a negative error code on failure.
 */
int use_semaphore(unsigned int init_val) {
    sem_t sem;
    int ret = 0;

    if (sem_init(&sem, 0, init_val) != 0) {
        return -1; /* sem_init failed */
    }

    /* Acquire the semaphore */
    if (sem_wait(&sem) != 0) {
        ret = -2; /* sem_wait failed */
        goto cleanup;
    }

    /* Critical section would go here */

    /* Release the semaphore */
    if (sem_post(&sem) != 0) {
        ret = -3; /* sem_post failed */
        goto cleanup;
    }

cleanup:
    if (sem_destroy(&sem) != 0) {
        /* If destruction fails, preserve the earlier error if any */
        if (ret == 0) ret = -4;
    }

    return ret;
}
