    public static SqlCommand CreateInsertCommand(SqlConnection connection, string tableName, DataRow row)
    {
        if (connection == null) throw new ArgumentNullException(nameof(connection));
        if (string.IsNullOrWhiteSpace(tableName)) throw new ArgumentException("Table name must be provided.", nameof(tableName));
        if (row == null) throw new ArgumentNullException(nameof(row));

        var command = connection.CreateCommand();

        var columns = row.Table.Columns.Cast<DataColumn>().Select(c => c.ColumnName).ToArray();
        var paramNames = columns.Select(c => "@" + c).ToArray();

        command.CommandText = $"INSERT INTO [{tableName}] ({string.Join(", ", columns.Select(c => $"[{c}]"))}) VALUES ({string.Join(", ", paramNames)})";

        foreach (DataColumn column in row.Table.Columns)
        {
            var parameter = command.CreateParameter();
            parameter.ParameterName = "@" + column.ColumnName;
            parameter.Value = row[column] ?? DBNull.Value;

            // Optional: map .NET types to SqlDbType for stronger typing
            if (column.DataType == typeof(string))
                parameter.SqlDbType = SqlDbType.NVarChar;
            else if (column.DataType == typeof(int))
                parameter.SqlDbType = SqlDbType.Int;
            else if (column.DataType == typeof(DateTime))
                parameter.SqlDbType = SqlDbType.DateTime;
            else if (column.DataType == typeof(bool))
                parameter.SqlDbType = SqlDbType.Bit;
            else if (column.DataType == typeof(decimal))
                parameter.SqlDbType = SqlDbType.Decimal;
            else if (column.DataType == typeof(byte[]))
                parameter.SqlDbType = SqlDbType.VarBinary;
            // Add more type mappings as needed

            command.Parameters.Add(parameter);
        }

        return command;
    }
