/**
 * Generates a random integer between min (inclusive) and max (exclusive) using
 * cryptographically secure randomness.
 */
function secureRandomInt(min, max) {
  const range = max - min;
  if (range <= 0) return min;
  const uint32 = new Uint32Array(1);
  // Loop until the random value falls within an unbiased range
  const maxUint = 0xffffffff - (0xffffffff % range);
  let value;
  do {
    crypto.getRandomValues(uint32);
    value = uint32[0];
  } while (value > maxUint);
  return min + (value % range);
}

/**
 * Creates a star object with random position, velocity, and radius.
 * @param {CanvasRenderingContext2D} ctx - Canvas 2D rendering context.
 * @param {number} width - Canvas width.
 * @param {number} height - Canvas height.
 * @returns {{x:number,y:number,vx:number,vy:number,radius:number}} Star object.
 */
function createStar(ctx, width, height) {
  const x = secureRandomInt(0, width);
  const y = secureRandomInt(0, height);
  const vx = (secureRandomInt(-50, 51) / 1000); // velocity between -0.05 and 0.05
  const vy = (secureRandomInt(-50, 51) / 1000);
  const radius = secureRandomInt(1, 4); // radius between 1 and 3 pixels

  // Draw the star
  ctx.beginPath();
  ctx.arc(x, y, radius, 0, Math.PI * 2);
  ctx.fillStyle = '#FFFFFF';
  ctx.fill();

  return { x, y, vx, vy, radius };
}

/**
 * Generates a random number of stars (between minStars and maxStars) and draws them.
 * @param {CanvasRenderingContext2D} ctx - Canvas 2D rendering context.
 * @param {number} width - Canvas width.
 * @param {number} height - Canvas height.
 * @param {number} [minStars=5] - Minimum number of stars to generate.
 * @param {number} [maxStars=20] - Maximum number of stars to generate.
 * @returns {Array} Array of star objects.
 */
function generateStars(ctx, width, height, minStars = 5, maxStars = 20) {
  const starCount = secureRandomInt(minStars, maxStars + 1);
  const stars = [];
  for (let i = 0; i < starCount; i++) {
    stars.push(createStar(ctx, width, height));
  }
  return stars;
