/**
 * Decodes a Uint8Array or Buffer into a UTF-8 string.
 * Handles empty buffers and incomplete multi‑byte characters safely.
 *
 * @param {Uint8Array|Buffer} input - The binary data to decode.
 * @returns {string} The decoded string, or an empty string if input is empty.
 */
function decodeBuffer(input) {
  // Ensure we have a Uint8Array; Buffer is a subclass of Uint8Array in Node.js.
  if (!input || input.length === 0) {
    return "";
  }

  // Use the built‑in TextDecoder with streaming support.
  const decoder = new TextDecoder("utf-8", { fatal: false });

  // Decode the provided chunk; `stream: true` tells the decoder to keep state
  // for any incomplete multi‑byte characters.
  const decodedPart = decoder.decode(input, { stream: true });

  // Flush any remaining buffered bytes (e.g., an incomplete character at the end).
  const finalPart = decoder.decode();

  return decodedPart + finalPart;
}
